#include "Arduino.h"
#include "Buttons.h"

Button::Button(
  TFTFunc tft,
  const uint16_t* image,
  const uint16_t* image_touchdown,
  uint16_t width,
  uint16_t height,
  uint16_t posX,
  uint16_t posY,
  bool forcedState
)
  : getTFT(tft),
    image(image),
    image_touchdown(image_touchdown),
    width(width),
    height(height),
    posX(posX),
    posY(posY),
    forcedState(forcedState)
{}

bool Button::onClick(uint16_t x, uint16_t y, bool newState) {
  if (x >= posX && x < (posX + width) && y >= posY && y < (posY + height)) {
    draw(newState);

    if (!forcedState) {
      delay(BUTTON_PRESSED_DELAY);
      draw(!newState);
    }

    return true;
  }
  return false;
}

void Button::draw(bool pressed) {
  TFT_eSPI& tft = getTFT();

  const uint16_t* img = pressed ? image_touchdown : image;

  if (img) {
    tft.pushImage(posX, posY, width, height, img);
  } else {
    tft.fillRect(posX, posY, width, height, pressed ? TFT_DARKGREY : TFT_LIGHTGREY);
  }
}

